def product_share_rule(model, p, t):
    return model.x[p, t] <= 0.6 * sum(model.x[pp, t] for pp in model.p)
model.product_share = Constraint(model.p, model.t, rule=product_share_rule)

def min_product_rule(model, p):
    return sum(model.x[p, t] for t in model.t) >= 5
model.min_product = Constraint(model.p, rule=min_product_rule)

def period_floor_rule(model, t):
    return sum(model.x[p, t] for p in model.p) >= 10
model.period_floor = Constraint(model.t, rule=period_floor_rule)
